                  <p className="mt-1">Use o ticket que melhor representa o tipo de cliente que você deseja alcançar.</p>
                </div>
              </div>
            </div>
          </div>

          {message && <p className="text-red-500 text-sm font-medium">{message}</p>}

          <Button type="submit">
            <DollarSign size={20} />
